namespace sv_b02368e6afb2449e982dcd05efa5cc55.Client;

// Serializable DTO that carries the authenticated user's identity across
// the Server → WebAssembly boundary via PersistentComponentState.
public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_b02368e6afb2449e982dcd05efa5cc55.Client;

namespace sv_b02368e6afb2449e982dcd05efa5cc55.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that hardcodes a logged-in user
/// and persists the identity into PersistentComponentState so the
/// WebAssembly runtime can rehydrate it after takeover.
/// </summary>
public sealed class PersistingServerAuthenticationStateProvider
    : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly Task<AuthenticationState> _authState;
    private PersistingComponentStateSubscription _subscription;

    public PersistingServerAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;

        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        _authState = Task.FromResult(new AuthenticationState(user));

        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveAuto);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;

    private async Task OnPersistingAsync()
    {
        var state = await GetAuthenticationStateAsync();
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = principal.FindFirstValue(ClaimTypes.Email)!,
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            });
        }
    }

    public void Dispose() => _subscription.Dispose();
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_b02368e6afb2449e982dcd05efa5cc55.Client;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that rehydrates the
/// user identity from PersistentComponentState, which was serialized by the
/// server during prerendering.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (!persistentState.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo)
            || userInfo is null)
        {
            _authState = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var identity = new ClaimsIdentity(claims, authenticationType: "Persisted");
        _authState = Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

@page "/profile"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>
        <p><strong>Roles:</strong></p>
        <ul>
            @foreach (var role in context.User.FindAll(ClaimTypes.Role))
            {
                <li>@role.Value</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

